import { useState, useRef, useCallback, useMemo, useEffect } from 'react';
import { userHomeCoords, HOME_SCALE, GUEST_SCALE } from '../utils/starUtils';

const useUniverseCamera = (userId, hasOwnPosts) => {
    const stageRef = useRef(null);
    const dragStartRef = useRef(null);
    const lastPinchDist = useRef(null);
    const isPinching = useRef(false);
    const hasAdjustedZoom = useRef(false);

    // Flight state
    const isFlying = useRef(false);
    const flyAnimRef = useRef(null);
    const cameraRef = useRef(null);
    const zoomRef = useRef(null);

    const [stageSize, setStageSize] = useState({
        width: window.innerWidth,
        height: window.innerHeight,
    });

    const initialCamera = useMemo(() => {
        if (!userId) return { x: 0, y: 0 };
        return userHomeCoords(userId);
    }, [userId]);

    // Start logged-in users at HOME_SCALE; will adjust after first fetch if no posts
    const initialZoom = useMemo(() => (userId ? HOME_SCALE : GUEST_SCALE), [userId]);

    const [camera, setCamera] = useState(initialCamera);
    const [zoom, setZoom] = useState(initialZoom);
    const [isDragging, setIsDragging] = useState(false);

    // Keep refs in sync with state so flyTo reads fresh values without deps
    cameraRef.current = camera;
    zoomRef.current = zoom;

    // If logged-in user has no posts, zoom out so they can see other galaxies
    useEffect(() => {
        if (hasAdjustedZoom.current) return;
        if (hasOwnPosts === null) return; // still loading
        if (!userId) return; // guests already at GUEST_SCALE
        if (!hasOwnPosts) {
            hasAdjustedZoom.current = true;
            setCamera({ x: 0, y: 0 });
            setZoom(GUEST_SCALE);
        } else {
            hasAdjustedZoom.current = true;
        }
    }, [hasOwnPosts, userId]);

    // Resize
    useEffect(() => {
        const onResize = () => setStageSize({ width: window.innerWidth, height: window.innerHeight });
        window.addEventListener('resize', onResize);
        return () => window.removeEventListener('resize', onResize);
    }, []);

    // Cleanup flight on unmount
    useEffect(() => {
        return () => {
            if (flyAnimRef.current) {
                cancelAnimationFrame(flyAnimRef.current);
                flyAnimRef.current = null;
            }
            isFlying.current = false;
        };
    }, []);

    // Center world coords (for display)
    const centerWorld = useMemo(() => ({
        x: Math.round(camera.x),
        y: Math.round(camera.y),
    }), [camera]);

    // Layer transform helper
    const getLayerProps = useCallback((parallaxFactor) => ({
        x: stageSize.width / 2 - camera.x * parallaxFactor * zoom,
        y: stageSize.height / 2 - camera.y * parallaxFactor * zoom,
        scaleX: zoom,
        scaleY: zoom,
    }), [camera, zoom, stageSize]);

    // Viewport bounds at parallax 1.0 (for data fetching)
    const getViewportBounds = useCallback(() => {
        const halfW = (stageSize.width / 2) / zoom;
        const halfH = (stageSize.height / 2) / zoom;
        const pad = 200 / zoom;
        return {
            minX: camera.x - halfW - pad,
            maxX: camera.x + halfW + pad,
            minY: camera.y - halfH - pad,
            maxY: camera.y + halfH + pad,
        };
    }, [camera, zoom, stageSize]);

    // --- Drag handling (Stage is NOT draggable) ---
    const handleMouseDown = useCallback((e) => {
        if (isFlying.current) return;
        // Only left button for mouse
        if (e.evt.button !== undefined && e.evt.button !== 0) return;
        dragStartRef.current = {
            pointerX: e.evt.clientX ?? e.evt.touches?.[0]?.clientX,
            pointerY: e.evt.clientY ?? e.evt.touches?.[0]?.clientY,
            camX: camera.x,
            camY: camera.y,
        };
        setIsDragging(true);
    }, [camera]);

    const handleMouseMove = useCallback((e) => {
        if (!dragStartRef.current) return;
        if (isPinching.current) return;
        const px = e.evt.clientX ?? e.evt.touches?.[0]?.clientX;
        const py = e.evt.clientY ?? e.evt.touches?.[0]?.clientY;
        if (px == null || py == null) return;
        const dx = (px - dragStartRef.current.pointerX) / zoom;
        const dy = (py - dragStartRef.current.pointerY) / zoom;
        setCamera({
            x: dragStartRef.current.camX - dx,
            y: dragStartRef.current.camY - dy,
        });
    }, [zoom]);

    const handleMouseUp = useCallback(() => {
        dragStartRef.current = null;
        setIsDragging(false);
        isPinching.current = false;
        lastPinchDist.current = null;
    }, []);

    // --- Wheel zoom ---
    const handleWheel = useCallback((e) => {
        e.evt.preventDefault();
        if (isFlying.current) return;

        const stage = stageRef.current;
        if (!stage) return;

        const pointer = stage.getPointerPosition();
        if (!pointer) return;

        const screenCenterX = stageSize.width / 2;
        const screenCenterY = stageSize.height / 2;

        const scaleBy = 1.08;
        const direction = e.evt.deltaY > 0 ? -1 : 1;
        const oldZoom = zoom;
        const newZoom = Math.min(Math.max(
            direction > 0 ? oldZoom * scaleBy : oldZoom / scaleBy,
            0.02
        ), 5);

        // World point under cursor before zoom
        const worldX = camera.x + (pointer.x - screenCenterX) / oldZoom;
        const worldY = camera.y + (pointer.y - screenCenterY) / oldZoom;

        // Adjust camera so same world point stays under cursor
        setCamera({
            x: worldX - (pointer.x - screenCenterX) / newZoom,
            y: worldY - (pointer.y - screenCenterY) / newZoom,
        });
        setZoom(newZoom);
    }, [zoom, camera, stageSize]);

    // --- Touch / Pinch ---
    const handleTouchMove = useCallback((e) => {
        if (isFlying.current) return;

        const touch = e.evt;
        if (touch.touches.length === 2) {
            // Pinch zoom
            isPinching.current = true;
            touch.preventDefault();

            const t1 = touch.touches[0];
            const t2 = touch.touches[1];
            const dist = Math.hypot(t2.clientX - t1.clientX, t2.clientY - t1.clientY);

            if (lastPinchDist.current === null) {
                lastPinchDist.current = dist;
                return;
            }

            const oldZoom = zoom;
            const newZoom = Math.min(Math.max(oldZoom * (dist / lastPinchDist.current), 0.02), 5);
            lastPinchDist.current = dist;

            const centerX = (t1.clientX + t2.clientX) / 2;
            const centerY = (t1.clientY + t2.clientY) / 2;
            const screenCenterX = stageSize.width / 2;
            const screenCenterY = stageSize.height / 2;

            const worldX = camera.x + (centerX - screenCenterX) / oldZoom;
            const worldY = camera.y + (centerY - screenCenterY) / oldZoom;

            setCamera({
                x: worldX - (centerX - screenCenterX) / newZoom,
                y: worldY - (centerY - screenCenterY) / newZoom,
            });
            setZoom(newZoom);
        } else if (touch.touches.length === 1 && !isPinching.current) {
            // Single finger drag — handled by mouseMove logic
            handleMouseMove(e);
        }
    }, [zoom, camera, stageSize, handleMouseMove]);

    const handleTouchEnd = useCallback(() => {
        lastPinchDist.current = null;
        if (isPinching.current) {
            isPinching.current = false;
            dragStartRef.current = null;
        }
    }, []);

    const stageEvents = useMemo(() => ({
        onMouseDown: handleMouseDown,
        onMouseMove: handleMouseMove,
        onMouseUp: handleMouseUp,
        onWheel: handleWheel,
        onTouchStart: handleMouseDown,
        onTouchMove: handleTouchMove,
        onTouchEnd: handleTouchEnd,
    }), [handleMouseDown, handleMouseMove, handleMouseUp, handleWheel, handleTouchMove, handleTouchEnd]);

